        catch (final NoSuchMethodException ignore) { // NOPMD
            // Ignore
        }
    }

    int currentMatch = 0;
    boolean ambiguous = false;

    // Then - with type conversion
    final Method[] methods = targetClass.getMethods();
    for (final Method method2 : methods) {
