                    currentMatch = match;
                    ambiguous = false;
                }
                else if (match == currentMatch) {
                    ambiguous = true;
                }
            }
        }
    }
    if (ambiguous) {
        throw new JXPathException("Ambiguous method call: " + name);
    }
    return method;
}

